// Highlights page
func formatHighlightTimestamp(highlightedAt time.Time, startedAt time.Time, valid bool) string {
	if !valid {
		return ""
	}
	return durafmt.Parse(highlightedAt.Sub(startedAt).Truncate(time.Second)).String()
}

